import React from "react";
import { Link } from "react-router-dom";
import Logo from "../assets/Logo.svg"

const Navbar = (props)=> {
    let isLoggedIn = props.isLoggedIn;
    let setIsLoggedIn = props.setIsLoggedIn;


    return (
        <div className="flex gap-5 justify-evenly py-1">
            <Link to="/">
             <img src= {Logo} alt="Logo" width={160} height={32} loading="lazy"></img> 
            </Link>
            <nav>
                <ul className="flex gap-3 ">
                    <li>
                        <Link to="/" className="text-white hover:text-gray-300">Home</Link>
                    </li>
                    <li>
                        <Link to="/" className="text-white hover:text-gray-300">about</Link>
                    </li>
                    <li>
                        <Link to="/" className="text-white hover:text-gray-300">contact us</Link>
                    </li>
                </ul>
            </nav>

            {/* login-signin-logout-dashboard */}

            <div className="flex ml-5 mr-3 gap-3">
                  { !isLoggedIn &&
                    <Link to="/login">
                        <button className="text-white ">Login</button>
                    </Link>
                  }
                  { !isLoggedIn &&
                    <Link to="/signup">
                        <button className="text-white ">sign up</button>
                    </Link>
                  }
                  { isLoggedIn &&
                    <Link to="/">
                        <button className="text-white " onClick={()=>{
                            setI
                        }}>Logout</button>
                    </Link>
                  }
                  { isLoggedIn &&
                    <Link to="/dashboard">
                        <button className="text-white ">Dashboard</button>
                    </Link>
                  }




            </div>

        </div>
    )
}

export default Navbar;
